    uint256 amount1;
    (int24 tL, int24 tU, uint24 fee) = abi.decode(p.additionalData, (int24, int24, uint24));
    {
        IUniswapV3Pool pool = IUniswapV3Pool(factory.getPool(token0, token1, fee));
        bytes32 key = keccak256(abi.encodePacked(positionManager, tL, tU)); // AGGREGATE key

        (uint128 liquidity,,, uint128 tokensOwed0, uint128 tokensOwed1) = pool.positions(key); // Returns ALL liquidity from positionManager at these ticks

        (uint160 sqrtPriceX96,,,,,,) = pool.slot0();
